import React, { useState } from 'react';
import axios from 'axios';

function RegistroAlumno() {
    const [nombre, setNombre] = useState('');
    const [banner, setBanner] = useState('');

    const guardar = async () => {
        try {
            await axios.post('http://localhost:5286/api/Reporte/registrar', {
                name: nombre,
                idBanner: banner
            });
            alert("¡Estudiante guardado en la base de datos con éxito!");
            setNombre(''); 
            setBanner('');
        } catch (error) {
            alert("Error al intentar guardar el estudiante.");
        }
    };

    return (
        <div className="card">
            <h3>Registrar Nuevo Estudiante</h3>
            <div className="form-group">
                <input 
                    type="text"
                    className="custom-input"
                    placeholder="Nombre Completo (Ej. Daniel Cárdenas)" 
                    value={nombre} 
                    onChange={(e) => setNombre(e.target.value)} 
                />
                <input 
                    type="text"
                    className="custom-input"
                    placeholder="ID Banner (Ej. 17075)" 
                    value={banner} 
                    onChange={(e) => setBanner(e.target.value)} 
                />
                <button className="btn-primary" onClick={guardar}>
                    Guardar Estudiante
                </button>
            </div>
        </div>
    );
}

export default RegistroAlumno;
